B.DZ=s(["Karar ge\xe7ersiz olur.","Karar \u015fekl\xee/maddi anlamda kesinle\u015fir ve icra edilebilir h\xe2le gelir.","Dava yeniden ilk derece mahkemesinde g\xf6r\xfcl\xfcr.","Karar resen Yarg\u0131tay\u2019a g\xf6nderilir."],t.s)
B.Jx=new A.b3("kanun_06",B.bZ,"S\xfcresinde kanun yoluna ba\u015fvurulmayan bir karar bak\u0131m\u0131ndan sonu\xe7 nedir?",B.DZ,1,"Kanun yolu s\xfcresi i\xe7inde ba\u015fvurulmazsa veya kanun yolu kapal\u0131ysa karar kesinle\u015fir; kesinle\u015fen karar icra edilebilir ve kesin h\xfck\xfcm (res judicata) etkisi do\u011furur.")
B.DP=s(["BAM\u2019\u0131n t\xfcm kararlar\u0131 istisnas\u0131z temyiz edilebilir.","Kanunda say\u0131lan baz\u0131 kararlar (\xf6r. temyiz kesinlik s\u0131n\u0131r\u0131n\u0131n alt\u0131nda kalanlar) temyiz edilemez.","BAM kararlar\u0131 yaln\u0131zca Anayasa Mahkemesi\u2019nde incelenir.","BAM kararlar\u0131 hi\xe7bir \u015fekilde temyiz edilemez."],t.s)
B.J7=new A.b3("kanun_07",B.bZ,"B\xf6lge adliye mahkemesi kararlar\u0131n\u0131n temyiz edilebilirli\u011fi bak\u0131m\u0131ndan a\u015fa\u011f\u0131dakilerden hangisi do\u011frudur?",B.DP,1,"HMK m. 362: Miktar/de\u011feri belirli s\u0131n\u0131r\u0131 ge\xe7meyen davalara ili\u015fkin kararlar ile maddede say\u0131lan di\u011fer kararlar temyiz edilemez (kesindir). Bu s\u0131n\u0131r da y\u0131ll\u0131k olarak yeniden de\u011ferleme oran\u0131nda artar.")
