B.Jb=new A.b3("arabulucu_01",B.cD,"\u0130\u015f\xe7i-i\u015fveren aras\u0131ndaki kanuna/s\xf6zle\u015fmeye dayanan i\u015f\xe7ilik alaca\u011f\u0131 ve i\u015fe iade davalar\u0131nda arabuluculu\u011fun rol\xfc nedir?",B.Ee,1,"7036 say\u0131l\u0131 \u0130\u015f Mahkemeleri Kanunu m. 3: Kanuna, bireysel veya toplu i\u015f s\xf6zle\u015fmesine dayanan i\u015f\xe7i/i\u015fveren alaca\u011f\u0131, tazminat\u0131 ve i\u015fe iade taleplerinde arabulucuya ba\u015fvurulmu\u015f olmas\u0131 dava \u015fart\u0131d\u0131r.")
B.E3=s(["T\xfcm ticari davalar\u0131 istisnas\u0131z kapsar.","Konusu bir miktar paran\u0131n \xf6denmesi olan alacak ve tazminat taleplerini kapsar.","Yaln\u0131zca \u015firketler hukukundan do\u011fan davalar\u0131 kapsar.","Yaln\u0131zca kambiyo senetlerine ili\u015fkin davalar\u0131 kapsar."],t.s)
B.JB=new A.b3("arabulucu_02",B.cD,"Ticari davalarda dava \u015fart\u0131 olan arabuluculuk hangi t\xfcr talepleri kapsar?",B.E3,1,"TTK m. 5/A: Konusu bir miktar paran\u0131n \xf6denmesi olan alacak ve tazminat talepleri hakk\u0131nda ticari davalarda, dava a\xe7\u0131lmadan \xf6nce arabulucuya ba\u015fvurulmu\u015f olmas\u0131 dava \u015fart\u0131d\u0131r.")
B.F3=s(["Davay\u0131 esastan inceleyip karar verir.","Herhangi bir i\u015flem yapmaks\u0131z\u0131n, dava \u015fart\u0131 yoklu\u011fundan davan\u0131n usulden reddine karar verir.","Taraflar\u0131 uzla\u015fmaya zorlar ve davay\u0131 bekletir.","Davay\u0131 g\xf6revsizlikten reddeder."],t.s)
B.Jd=new A.b3("arabulucu_03",B.cD,"Dava \u015fart\u0131 olan arabuluculu\u011fa hi\xe7 ba\u015fvurulmadan do\u011frudan dava a\xe7\u0131l\u0131rsa mahkeme ne yapar?",B.F3,1,"7036 m. 3/2 (ve TTK m. 5/A atf\u0131): Arabulucuya ba\u015fvurulmadan dava a\xe7\u0131ld\u0131\u011f\u0131n\u0131n anla\u015f\u0131lmas\u0131 h\xe2linde, herhangi bir i\u015flem yap\u0131lmaks\u0131z\u0131n dava, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddedilir. Bu, konunun en kritik final bilgisidir.")
B.F6=s(["Do\u011frudan davay\u0131 esastan reddeder.","Davac\u0131ya, son tutana\u011f\u0131n bir haftal\u0131k kesin s\xfcre i\xe7inde sunulmas\u0131 i\xe7in ihtarda bulunur; sunulmazsa dava usulden reddedilir.","Tutana\u011f\u0131 resen arabuluculuk b\xfcrosundan ister.","Davay\u0131 hi\xe7bir uyar\u0131 yapmadan g\xf6revsizlikle reddeder."],t.s)
B.Jn=new A.b3("arabulucu_04",B.cD,"Arabuluculuk dava \u015fart\u0131 olan bir davada, anla\u015fmaya var\u0131lamad\u0131\u011f\u0131na ili\u015fkin son tutanak dava dilek\xe7esine eklenmemi\u015fse mahkeme \xf6nce ne yapar?",B.F6,1,"7036 m. 3/2: Arabulucuya ba\u015fvurulmu\u015f ancak son tutanak eklenmemi\u015fse, mahkeme davac\u0131ya bir haftal\u0131k kesin s\xfcre verir; bu s\xfcre i\xe7inde sunulmazsa dava dilek\xe7esi kar\u015f\u0131 tarafa tebli\u011fe \xe7\u0131kar\u0131lmadan dava usulden reddedilir. (Hi\xe7 ba\u015fvurulmam\u0131\u015fsa s\xfcre verilmeden do\u011frudan reddedilir.)")
B.Fl=s(["K\u0131dem tazminat\u0131 talebi","Fazla mesai \xfccreti alaca\u011f\u0131","\u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131","\u0130hbar tazminat\u0131 talebi"],t.s)
B.Jg=new A.b3("arabulucu_05",B.cD,"A\u015fa\u011f\u0131dakilerden hangisi i\u015f hukukunda dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 DI\u015eINDADIR?",B.Fl,2,"7036 m. 3: \u0130\u015f kazas\u0131 veya meslek hastal\u0131\u011f\u0131ndan kaynaklanan maddi-manevi tazminat davalar\u0131 ile bunlarla ilgili tespit, itiraz ve r\xfccu davalar\u0131 dava \u015fart\u0131 arabuluculu\u011fun kapsam\u0131 d\u0131\u015f\u0131ndad\u0131r.")
B.ET=s(["\xdc\xe7 hafta i\xe7inde; zorunlu h\xe2llerde en fazla bir hafta uzat\u0131labilir.","\u0130ki ay i\xe7inde; uzatma m\xfcmk\xfcn de\u011fildir.","Bir y\u0131l i\xe7inde.","S\xfcre \xf6ng\xf6r\xfclmemi\u015ftir."],t.s)
B.Jq=new A.b3("arabulucu_06",B.cD,"Dava \u015fart\u0131 arabuluculukta arabulucu, ba\u015fvuru tarihinden itibaren s\xfcreci kural olarak ne kadar s\xfcrede tamamlamal\u0131d\u0131r?",B.ET,0,"\u0130\u015f ve ticari uyu\u015fmazl\u0131klarda arabulucu, g\xf6revlendirildi\u011fi tarihten itibaren s\xfcreci \xfc\xe7 hafta i\xe7inde sonu\xe7land\u0131r\u0131r; bu s\xfcre zorunlu h\xe2llerde arabulucu taraf\u0131ndan en fazla bir hafta uzat\u0131labilir.")
